#include "hub75_matrix.h"
#include <ESP32-HUB75-MatrixPanel-I2S-DMA.h>
static MatrixPanel_I2S_DMA*dma=nullptr;
void hub75_setup(){HUB75_I2S_CFG cfg(64,32,1);dma=new MatrixPanel_I2S_DMA(cfg);dma->begin();dma->setBrightness8(90);dma->clearScreen();Serial.println("[hub75] OK 64x32");}
void hub75_clear(){if(dma)dma->clearScreen();}
void hub75_pixel(int x,int y,uint8_t r,uint8_t g,uint8_t b){if(dma)dma->drawPixelRGB888(x,y,r,g,b);}
void hub75_text(int x,int y,const char*t,uint8_t r,uint8_t g,uint8_t b){if(!dma)return;dma->setTextColor(dma->color565(r,g,b));dma->setCursor(x,y);dma->print(t);}
void hub75_fill_rect(int x,int y,int w,int h,uint8_t r,uint8_t g,uint8_t b){if(dma)dma->fillRect(x,y,w,h,dma->color565(r,g,b));}
